def process_user_data(user_record):
    if not user_record:
        return None

    username = user_record.get("username")
    email = user_record.get("email")
    account_type = user_record.get("type", "standard")

    if not username or not email:
        return {"error": "missing_fields"}

    processed_data = {
        "user_id": hash(username),
        "contact": email.lower().strip(),
        "status": "active"
    }

    if account_type == "admin":
        processed_data["permissions"] = ["read", "write", "delete"]
    elif account_type == "moderator":
        processed_data["permissions"] = ["read", "write"]
    else:
        processed_data["permissions"] = ["read"]

    if len(username) > 50:
        processed_data["username_short"] = username[:50]
    else:
        processed_data["username_short"] = username

    return processed_data

